const raw = $json.output;

try {
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  return [{ json: parsed }];
} catch (error) {
  return [{
    json: {
      job_link: '',
      has_job_link: false,
      reply_message: 'Please send a valid job link you want me to analyze.',
      parse_error: String(error),
      raw_output: raw
    }
  }];
}

